[asy]
pair O,A,C,B,D;
O=(0,0);
A=(-12,-16); C=(12,-16);
D=(0,-16); B=(0,20);
draw(Circle(O,20),linewidth(0.7));
draw(A--B--C--cycle,linewidth(0.7));
draw(B--D,linewidth(0.7));
draw(O--A,linewidth(0.7));
label("$r$",(0.6,10),W);
label("$r$",(-5.3,-7.7),NW);
label("1",(-6,-16),N);
label("3",(-6,0),NW);
label("$A$",A,SW);
label("$B$",B,N);
label("$C$",C,SE);
label("$D$",(0,-15.7),S);
label("$O$",O,E);
[/asy]

